     1→import { types as t } from "@marko/compiler";
     2→import { getProgram } from "@marko/compiler/babel-utils";
     3→
     4→import { toAccess } from "../../html/serializer";
     5→import { finalizeFunctionRegistry } from "../visitors/function";
     6→import type { InputSerializeReasons } from "../visitors/program";
     7→import { forEachIdentifierPath } from "./for-each-identifier";
     8→import { generateUid } from "./generate-uid";
     9→import { getAccessorPrefix, getAccessorProp } from "./get-accessor-char";
    10→import { getExprRoot, getFnRoot } from "./get-root";
    11→import isInvokedFunction from "./is-invoked-function";
    12→import { isOptimize } from "./marko-config";
    13→import {
    14→  addSorted,
    15→  concat,
    16→  filter,
    17→  find,
    18→  findSorted,
    19→  forEach,
    20→  type Many,
    21→  type OneMany,
    22→  type Opt,
    23→  push,
    24→  Sorted,
    25→} from "./optional";
    26→import { getScopeExpression } from "./scope-read";
    27→import {
    28→  forEachSection,
    29→  getCommonSection,
    30→  getDirectClosures,
    31→  getOrCreateSection,
    32→  isDynamicClosure,
    33→  isSameOrChildSection,
    34→  isSerializedSection,
    35→  type Section,
    36→  sectionUtil,
    37→} from "./sections";
    38→import {
    39→  addBindingSerializeReason,
    40→  addBindingSerializeReasonExpr,
    41→  addOwnersSerializeReason,
    42→  addSectionSerializeReason,
    43→  addSectionSerializeReasonExpr,
    44→  addSectionSerializeReasonRef,
    45→  applySerializeReasonExprs,
    46→  finalizeSectionSerializeReasons,
    47→  forceBindingSerialize,
    48→  forceOwnersSerialize,
    49→  forceSectionSerialize,
    50→  getBindingSerializeReason,
    51→  getSerializeSourcesForExpr,
    52→  isBindingForceSerialized,
    53→  mergeSerializeReasons,
    54→  type SerializeReason,
    55→} from "./serialize-reasons";
    56→import { getHoistFunctionIdentifier } from "./signals";
    57→import { createProgramState } from "./state";
    58→import { toMemberExpression } from "./to-property-name";
    59→import withPreviousLocation from "./with-previous-location";
    60→
    61→const kIsInvoked = Symbol("hoist is invoked");
    62→export const kBranchSerializeReason = Symbol("branch serialize reason");
    63→export type Aliases = undefined | Binding | { [property: string]: Aliases };
    64→
    65→export enum BindingType {
    66→  dom,
    67→  let,
    68→  input,
    69→  param,
    70→  local,
    71→  derived,
    72→  hoist,
    73→  // todo: constant
    74→}
    75→
    76→export interface Sources {
    77→  state: Opt<Binding>;
    78→  input: Opt<InputBinding>;
    79→}
    80→
    81→export interface Binding {
    82→  id: number;
    83→  name: string;
    84→  type: BindingType;
    85→  loc: t.SourceLocation | null;
    86→  section: Section;
    87→  closureSections: Opt<Section>;
    88→  assignmentSections: Opt<Section>;
    89→  sources: undefined | Sources;
    90→  aliases: Set<Binding>;
    91→  hoists: Map<Section, Binding>;
    92→  property: string | undefined;
    93→  propertyAliases: Map<string, Binding>;
    94→  excludeProperties: Opt<string>;
    95→  upstreamAlias: Binding | undefined;
    96→  downstreamExpressions: Set<ReferencedExtra>;
    97→  scopeOffset: Binding | undefined;
    98→  export: string | undefined;
    99→  declared: boolean;
   100→  nullable: boolean;
   101→}
   102→
   103→export interface InputBinding extends Binding {
   104→  type: BindingType.input;
   105→}
   106→
   107→export type ReferencedBindings = Opt<Binding>;
   108→export type Intersection = Many<Binding>;
   109→
   110→type FnExtra = (
   111→  | t.FunctionExpressionExtra
   112→  | t.ArrowFunctionExpressionExtra
   113→  | t.FunctionDeclarationExtra
   114→) & { section: Section };
   115→
   116→interface Read {
   117→  binding: Binding;
   118→  node: undefined | t.MemberExpression | t.Identifier;
   119→}
   120→
   121→declare module "@marko/compiler/dist/types" {
   122→  export interface NodeExtra {
   123→    section?: Section;
   124→    referencedBindings?: ReferencedBindings;
   125→    downstream?: {
   126→      bindings: OneMany<Binding>;
   127→      excludeProperties: undefined | Set<string>;
   128→    };
   129→    binding?: Binding;
   130→    assignment?: Binding;
   131→    assignmentTo?: Binding;
   132→    read?: { binding: Binding; props: Opt<string> };
   133→    pruned?: true;
   134→    isEffect?: true;
   135→    [kIsInvoked]?: true;
   136→  }
   137→
   138→  export interface FunctionExtra {
   139→    referencedBindingsInFunction?: ReferencedBindings;
   140→  }
   141→
   142→  export interface ArrowFunctionExpressionExtra extends FunctionExtra {}
   143→  export interface FunctionDeclarationExtra extends FunctionExtra {}
   144→  export interface FunctionExpressionExtra extends FunctionExtra {}
   145→}
   146→
   147→const [getBindings] = createProgramState(() => new Set<Binding>());
   148→const [getNextBindingId, setNextBindingId] = createProgramState(() => 0);
   149→export function createBinding(
   150→  name: string,
   151→  type: Binding["type"],
   152→  section: Section,
   153→  upstreamAlias?: Binding["upstreamAlias"],
   154→  property?: string,
   155→  excludeProperties?: Opt<string>,
   156→  loc: t.SourceLocation | null = null,
   157→  declared = false,
   158→): Binding {
   159→  const id = getNextBindingId();
   160→  const binding: Binding = {
   161→    id,
   162→    name,
   163→    type,
   164→    loc,
   165→    section,
   166→    property,
   167→    declared,
   168→    closureSections: undefined,
   169→    assignmentSections: undefined,
   170→    excludeProperties,
   171→    sources: undefined,
   172→    aliases: new Set(),
   173→    hoists: new Map(),
   174→    propertyAliases: new Map(),
   175→    upstreamAlias,
   176→    downstreamExpressions: new Set(),
   177→    scopeOffset: undefined,
   178→    export: undefined,
   179→    nullable: excludeProperties === undefined,
   180→  };
   181→
   182→  if (property) {
   183→    if (declared) upstreamAlias!.nullable = false;
   184→    // TODO: should prefer declared properties as alias roots.
   185→    const propBinding = upstreamAlias!.propertyAliases.get(property);
   186→    if (propBinding) {
   187→      binding.property = undefined;
   188→      binding.upstreamAlias = propBinding;
   189→      propBinding.aliases.add(binding);
   190→    } else {
   191→      // TODO: check if default is used, if so an intermediate binding is needed
   192→      upstreamAlias!.propertyAliases.set(property, binding);
   193→    }
   194→  } else if (upstreamAlias) {
   195→    upstreamAlias.aliases.add(binding);
   196→  }
   197→
   198→  setNextBindingId(id + 1);
   199→  getBindings().add(binding);
   200→  return binding;
   201→}
   202→
   203→export function trackVarReferences(
   204→  tag: t.NodePath<t.MarkoTag>,
   205→  type: BindingType,
   206→  upstreamAlias?: Binding["upstreamAlias"],
   207→) {
   208→  const tagVar = tag.node.var;
   209→  if (tagVar) {
   210→    let canonicalUpstreamAlias = getCanonicalBinding(upstreamAlias);
   211→    if (canonicalUpstreamAlias) {
   212→      const { excludeProperties } = canonicalUpstreamAlias;
   213→      if (excludeProperties !== undefined) {
   214→        canonicalUpstreamAlias = canonicalUpstreamAlias.upstreamAlias!;
   215→      }
   216→      createBindingsAndTrackReferences(
   217→        tagVar,
   218→        canonicalUpstreamAlias.type,
   219→        tag.scope,
   220→        canonicalUpstreamAlias.section,
   221→        canonicalUpstreamAlias,
   222→        undefined,
   223→        excludeProperties,
   224→      );
   225→      return canonicalUpstreamAlias;
   226→    }
   227→
   228→    createBindingsAndTrackReferences(
   229→      tagVar,
   230→      type,
   231→      tag.scope,
   232→      getOrCreateSection(tag),
   233→      undefined,
   234→      undefined,
   235→      undefined,
   236→    );
   237→    return tagVar.extra?.binding;
   238→  }
   239→}
   240→
   241→export function trackParamsReferences(
   242→  body: t.NodePath<t.MarkoTagBody | t.Program>,
   243→  type: BindingType,
   244→  upstreamAlias?: Binding["upstreamAlias"],
   245→) {
   246→  const params = body.node.params;
   247→  if (body.node.body.length && params.length) {
   248→    const canonicalUpstreamAlias = getCanonicalBinding(upstreamAlias);
   249→    let section: Section;
   250→    if (canonicalUpstreamAlias) {
   251→      section = canonicalUpstreamAlias.section;
   252→      type = canonicalUpstreamAlias.type;
   253→    } else {
   254→      section = getOrCreateSection(body);
   255→    }
   256→    const paramsBinding =
   257→      canonicalUpstreamAlias ||
   258→      ((body.node.extra ??= {}).binding = createBinding(
   259→        generateUid("params"),
   260→        type,
   261→        section,
   262→        undefined,
   263→        undefined,
   264→      ));
   265→
   266→    section.params = paramsBinding;
   267→
   268→    for (let i = 0; i < params.length; i++) {
   269→      const param = params[i];
   270→      if (param.type === "RestElement") {
   271→        createBindingsAndTrackReferences(
   272→          param.argument,
   273→          type,
   274→          body.scope,
   275→          section,
   276→          paramsBinding,
   277→          undefined,
   278→          addNumericPropertiesUntil(undefined, i - 1),
   279→        );
   280→      } else if (t.isLVal(param)) {
   281→        createBindingsAndTrackReferences(
   282→          param,
   283→          type,
   284→          body.scope,
   285→          section,
   286→          paramsBinding,
   287→          i + "",
   288→          undefined,
   289→        );
   290→      }
   291→    }
   292→
   293→    return paramsBinding;
   294→  }
   295→}
   296→
   297→export function trackHoistedReference(
   298→  referencePath: t.NodePath<t.Identifier>,
   299→  binding: Binding,
   300→) {
   301→  const section = binding.section;
   302→  const referenceSection = getOrCreateSection(referencePath);
   303→  const hoistSection = getCommonSection(referenceSection, section);
   304→  const extra = (referencePath.node.extra ??= {});
   305→
   306→  let hoistedBinding = binding.hoists.get(hoistSection);
   307→  if (!hoistedBinding) {
   308→    binding.hoists.set(
   309→      hoistSection,
   310→      (hoistedBinding = createBinding(
   311→        generateUid("hoisted_" + referencePath.node.name),
   312→        BindingType.hoist,
   313→        hoistSection,
   314→        undefined,
   315→        undefined,
   316→        undefined,
   317→        binding.loc,
   318→        true,
   319→      )),
   320→    );
   321→
   322→    section.hoisted = bindingUtil.add(section.hoisted, binding);
   323→
   324→    let currentSection = section.parent;
   325→    while (currentSection && currentSection !== hoistSection) {
   326→      currentSection.isHoistThrough = true;
   327→      currentSection = currentSection.parent;
   328→    }
   329→  }
   330→
   331→  if (isInvokedFunction(referencePath)) {
   332→    extra.read = createRead(hoistedBinding, undefined);
   333→    extra.section = referenceSection;
   334→    extra[kIsInvoked] = true;
   335→  } else {
   336→    trackReference(referencePath, hoistedBinding);
   337→  }
   338→
   339→  referenceSection.referencedHoists = bindingUtil.add(
   340→    referenceSection.referencedHoists,
   341→    hoistedBinding,
   342→  );
   343→}
   344→
   345→function trackReferencesForBinding(babelBinding: t.Binding, binding: Binding) {
   346→  const { referencePaths, constantViolations } = babelBinding;
   347→
   348→  for (const referencePath of referencePaths) {
   349→    const referenceSection = getOrCreateSection(referencePath);
   350→    if (isSameOrChildSection(binding.section, referenceSection)) {
   351→      if (
   352→        binding.type === BindingType.local &&
   353→        referenceSection === binding.section
   354→      ) {
   355→        continue;
   356→      }
   357→      trackReference(referencePath as t.NodePath<t.Identifier>, binding);
   358→    } else {
   359→      trackHoistedReference(referencePath as t.NodePath<t.Identifier>, binding);
   360→    }
   361→  }
   362→
   363→  for (const ref of constantViolations) {
   364→    if (ref.isUpdateExpression()) {
   365→      trackAssignment(ref.get("argument"), binding);
   366→    } else if (ref.isAssignmentExpression()) {
   367→      trackAssignment(ref.get("left"), binding);
   368→
   369→      if (ref.node.operator !== "=") {
   370→        /*
   371→         * https://github.com/babel/babel/issues/11313
   372→         * We need this so we can handle `+=` and friends
   373→         */
   374→        const left = ref.get("left");
   375→        if (left.isIdentifier()) {
   376→          trackReference(left, binding);
   377→        }
   378→      }
   379→    }
   380→  }
   381→}
   382→
   383→function trackAssignment(
   384→  assignment: t.NodePath<
   385→    t.AssignmentExpression["left"] | t.UpdateExpression["argument"]
   386→  >,
   387→  binding: Binding,
   388→) {
   389→  const fnRoot = getFnRoot(assignment);
   390→  const fnExtra = fnRoot && ((fnRoot.node.extra ??= {}) as FnExtra);
   391→  const section = getOrCreateSection(assignment);
   392→  setReferencesScope(assignment);
   393→  forEachIdentifierPath(assignment, (id) => {
   394→    if (id.node.name === binding.name) {
   395→      const extra = (id.node.extra ??= {}) as AssignedBindingExtra;
   396→
   397→      if (binding.upstreamAlias && binding.property !== undefined) {
   398→        const changePropName = binding.property + "Change";
   399→        const changeBinding =
   400→          binding.upstreamAlias.propertyAliases.get(changePropName) ||
   401→          createBinding(
   402→            generateUid(changePropName),
   403→            BindingType.derived,
   404→            binding.section,
   405→            binding.upstreamAlias,
   406→            changePropName,
   407→            undefined,
   408→            id.node.loc,
   409→            true,
   410→          );
   411→        extra.assignmentTo = changeBinding;
   412→        addReadToExpression(id, changeBinding);
   413→      }
   414→
   415→      binding.assignmentSections = sectionUtil.add(
   416→        binding.assignmentSections,
   417→        section,
   418→      );
   419→      extra.assignment = binding;
   420→      extra.section = section;
   421→      extra.fnExtra = fnExtra;
   422→    }
   423→  });
   424→}
   425→
   426→export function setReferencesScope(path: t.NodePath<any>) {
   427→  const fnRoot = getFnRoot(path);
   428→  if (fnRoot) {
   429→    (fnRoot.node.extra ??= {}).referencesScope = true;
   430→  }
   431→}
   432→
   433→function createBindingsAndTrackReferences(
   434→  lVal: t.LVal,
   435→  type: BindingType,
   436→  scope: t.Scope,
   437→  section: Section,
   438→  upstreamAlias: Binding["upstreamAlias"] | undefined,
   439→  property: string | undefined,
   440→  excludeProperties: Opt<string>,
   441→) {
   442→  switch (lVal.type) {
   443→    case "Identifier":
   444→      trackReferencesForBinding(
   445→        scope.getBinding(lVal.name)!,
   446→        ((lVal.extra ??= {}).binding = createBinding(
   447→          lVal.name,
   448→          type,
   449→          section,
   450→          upstreamAlias,
   451→          property,
   452→          excludeProperties,
   453→          lVal.loc,
   454→          true,
   455→        )),
   456→      );
   457→      break;
   458→    case "ObjectPattern": {
   459→      const patternBinding =
   460→        (property
   461→          ? upstreamAlias!.propertyAliases.get(property)
   462→          : upstreamAlias) ||
   463→        ((lVal.extra ??= {}).binding = createBinding(
   464→          generateUid(property || "pattern"),
   465→          type,
   466→          section,
   467→          upstreamAlias,
   468→          property,
   469→          excludeProperties,
   470→          lVal.loc,
   471→        ));
   472→
   473→      const hasRest =
   474→        lVal.properties[lVal.properties.length - 1]?.type === "RestElement";
   475→      for (const prop of lVal.properties) {
   476→        if (prop.type === "RestElement") {
   477→          createBindingsAndTrackReferences(
   478→            prop.argument,
   479→            type,
   480→            scope,
   481→            section,
   482→            patternBinding,
   483→            property,
   484→            excludeProperties,
   485→          );
   486→        } else {
   487→          let key: string;
   488→
   489→          if (prop.key.type === "Identifier") {
   490→            key = prop.key.name;
   491→          } else if (prop.key.type === "StringLiteral") {
   492→            key = prop.key.value;
   493→          } else {
   494→            // TODO: it should be a computed value
   495→            throw new Error("computed keys not supported in object pattern");
   496→          }
   497→
   498→          if (hasRest) {
   499→            excludeProperties = propsUtil.add(excludeProperties, key);
   500→          }
   501→
   502→          if (t.isLVal(prop.value)) {
   503→            createBindingsAndTrackReferences(
   504→              prop.value,
   505→              type,
   506→              scope,
   507→              section,
   508→              patternBinding,
   509→              key,
   510→              undefined,
   511→            );
   512→          }
   513→        }
   514→      }
   515→      break;
   516→    }
   517→    case "ArrayPattern": {
   518→      const patternBinding =
   519→        (property
   520→          ? upstreamAlias!.propertyAliases.get(property)
   521→          : upstreamAlias) ||
   522→        ((lVal.extra ??= {}).binding = createBinding(
   523→          generateUid(property || "pattern"),
   524→          type,
   525→          section,
   526→          upstreamAlias,
   527→          property,
   528→          excludeProperties,
   529→          lVal.loc,
   530→        ));
   531→
   532→      let i = -1;
   533→      for (const element of lVal.elements) {
   534→        i++;
   535→        if (element) {
   536→          if (element.type === "RestElement") {
   537→            excludeProperties = addNumericPropertiesUntil(
   538→              excludeProperties,
   539→              i - 1,
   540→            );
   541→            createBindingsAndTrackReferences(
   542→              element.argument,
   543→              type,
   544→              scope,
   545→              section,
   546→              patternBinding,
   547→              property,
   548→              excludeProperties,
   549→            );
   550→          } else if (t.isLVal(element)) {
   551→            createBindingsAndTrackReferences(
   552→              element,
   553→              type,
   554→              scope,
   555→              section,
   556→              patternBinding,
   557→              `${i}`,
   558→              undefined,
   559→            );
   560→          }
   561→        }
   562→      }
   563→      break;
   564→    }
   565→    case "AssignmentPattern":
   566→      // TODO: this makes a default value an alias,
   567→      // but it really should be a computed value
   568→      createBindingsAndTrackReferences(
   569→        lVal.left,
   570→        type,
   571→        scope,
   572→        section,
   573→        upstreamAlias,
   574→        property,
   575→        undefined,
   576→      );
   577→
   578→      if (lVal.left.extra?.binding) {
   579→        (lVal.right.extra ??= {}).downstream = {
   580→          bindings: lVal.left.extra.binding,
   581→          excludeProperties: undefined,
   582→        };
   583→      }
   584→      break;
   585→  }
   586→}
   587→
   588→function trackReference(
   589→  referencePath: t.NodePath<t.Identifier>,
   590→  binding: Binding,
   591→) {
   592→  let root: t.NodePath<t.Identifier> | t.NodePath<t.MemberExpression> =
   593→    referencePath;
   594→  let reference = binding;
   595→  let propPath = binding.name;
   596→
   597→  while (true) {
   598→    const { parent } = root;
   599→    if (!t.isMemberExpression(parent)) break;
   600→
   601→    const prop = getMemberExpressionPropString(parent);
   602→    if (prop === undefined) break;
   603→
   604→    if (
   605→      reference.upstreamAlias &&
   606→      reference.excludeProperties !== undefined &&
   607→      !propsUtil.has(reference.excludeProperties, prop)
   608→    ) {
   609→      reference = reference.upstreamAlias;
   610→    }
   611→
   612→    if (reference.propertyAliases.has(prop)) {
   613→      root = root.parentPath as t.NodePath<t.MemberExpression>;
   614→      reference = reference.propertyAliases.get(prop)!;
   615→      propPath = reference.name;
   616→      continue;
   617→    }
   618→
   619→    if (isInvokedFunction(root.parentPath) && !isEventOrChangeHandler(prop)) {
   620→      break;
   621→    }
   622→
   623→    root = root.parentPath as t.NodePath<t.MemberExpression>;
   624→    reference = createBinding(
   625→      (propPath += `_${prop.replace(/[^a-zA-Z0-9_$]/g, "_")}`),
   626→      reference.type,
   627→      reference.section,
   628→      reference,
   629→      prop,
   630→    );
   631→  }
   632→
   633→  addReadToExpression(root, reference);
   634→}
   635→
   636→const [getMergedReferences] = createProgramState(
   637→  () => new Map<t.Node, (t.Node | undefined)[]>(),
   638→);
   639→export function mergeReferences<T extends t.Node>(
   640→  section: Section,
   641→  target: T,
   642→  nodes: (t.Node | undefined)[],
   643→): NonNullable<T["extra"]> & ReferencedExtra {
   644→  const targetExtra = (target.extra ??= {});
   645→  targetExtra.section = section;
   646→  getMergedReferences().set(target, nodes);
   647→  return targetExtra as NonNullable<T["extra"]> & ReferencedExtra;
   648→}
   649→
   650→export function compareReferences(
   651→  a: ReferencedBindings,
   652→  b: ReferencedBindings,
   653→) {
   654→  return a === b
   655→    ? 0
   656→    : a
   657→      ? b
   658→        ? Array.isArray(a)
   659→          ? Array.isArray(b)
   660→            ? compareIntersections(a, b)
   661→            : -1
   662→          : Array.isArray(b)
   663→            ? 1
   664→            : bindingUtil.compare(a, b)
   665→        : 1
   666→      : b
   667→        ? -1
   668→        : 0;
   669→}
   670→
   671→/**
   672→ * reference group priority is sorted by number of references,
   673→ * then if needed by reference order.
   674→ */
   675→function compareIntersections(a: Intersection, b: Intersection) {
   676→  const len = a.length;
   677→  const lenDelta = len - b.length;
   678→  if (lenDelta !== 0) {
   679→    return lenDelta;
   680→  }
   681→
   682→  for (let i = 0; i < len; i++) {
   683→    const compareResult = bindingUtil.compare(a[i], b[i]);
   684→    if (compareResult !== 0) {
   685→      return compareResult;
   686→    }
   687→  }
   688→
   689→  return 0;
   690→}
   691→
   692→export function finalizeReferences() {
   693→  const bindings = getBindings();
   694→  const readsByExpression = getReadsByExpression();
   695→  const readsByFn = getReadsByFunction();
   696→  const mergedReferences = getMergedReferences();
   697→
   698→  if (mergedReferences.size) {
   699→    for (const [target, nodes] of mergedReferences) {
   700→      const targetExtra = target.extra as ReferencedExtra;
   701→      let reads = readsByExpression.get(targetExtra);
   702→      let { isEffect } = targetExtra;
   703→      for (const node of nodes) {
   704→        const extra = node?.extra;
   705→        if (extra) {
   706→          setCanonicalExtra(extra, targetExtra);
   707→          if (isReferencedExtra(extra)) {
   708→            const additionalReads = readsByExpression.get(extra);
   709→            isEffect ||= extra.isEffect;
   710→            if (additionalReads) {
   711→              reads = concat(reads, additionalReads);
   712→              readsByExpression.delete(extra);
   713→            }
   714→          }
   715→        }
   716→      }
   717→
   718→      readsByExpression.set(targetExtra, reads);
   719→      targetExtra.isEffect = isEffect;
   720→    }
   721→  }
   722→
   723→  const intersectionsBySection = new Map<Section, Intersection[]>();
   724→  for (const [expr, reads] of readsByExpression) {
   725→    if (isReferencedExtra(expr)) {
   726→      expr.referencedBindings = resolveReferencedBindings(
   727→        expr,
   728→        reads,
   729→        intersectionsBySection,
   730→      );
   731→      forEach(expr.referencedBindings, (binding) => {
   732→        binding.downstreamExpressions.add(expr);
   733→      });
   734→    }
   735→  }
   736→
   737→  for (const [fn, reads] of readsByFn) {
   738→    fn.referencedBindingsInFunction = resolveReferencedBindings(
   739→      fn,
   740→      reads,
   741→      intersectionsBySection,
   742→    );
   743→
   744→    forEach(fn.referencedBindingsInFunction, (binding) =>
   745→      forceBindingSerialize(binding.section, binding),
   746→    );
   747→  }
   748→
   749→  for (const binding of bindings) {
   750→    if (binding.type !== BindingType.dom && !binding.upstreamAlias) {
   751→      pruneBinding(bindings, binding);
   752→    }
   753→  }
   754→
   755→  for (const binding of bindings) {
   756→    const { name, section } = binding;
   757→    if (binding.type !== BindingType.dom) {
   758→      resolveBindingSources(binding);
   759→      if (binding.hoists.size) {
   760→        forceBindingSerialize(binding.section, binding);
   761→      }
   762→
   763→      forEach(binding.assignmentSections, (assignedSection) =>
   764→        forceOwnersSerialize(assignedSection, section, getAccessorProp().Owner),
   765→      );
   766→
   767→      if (find(section.bindings, ({ name }) => name === binding.name)) {
   768→        /*
   769→          TODO: this will break if parent sections use the generated UID.
   770→          ```
   771→          let/_count
   772→          my-tag
   773→            let/count
   774→            div
   775→              let/count
   776→              -- ${_count}
   777→          ```
   778→        */
