   876→              !isBindingForceSerialized(section, binding1) &&
   877→              !isSupersetSources(binding1, binding2)
   878→            ) {
   879→              if (!isSameOrChildSection(section, binding1.section)) {
   880→                addOwnersSerializeReason(
   881→                  section,
   882→                  binding1.section,
   883→                  mergeSerializeReasons(
   884→                    // TODO should check for an actual intersection, not just stateful
   885→                    binding1.sources,
   886→                    binding2.sources,
   887→                  ),
   888→                  getAccessorProp().Owner,
   889→                );
   890→              }
   891→
   892→              addBindingSerializeReason(
   893→                binding1.section,
   894→                binding1,
   895→                binding2.sources, // TODO should check for an actual intersection, not just binding2.sources stateful
   896→              );
   897→            }
   898→            if (
   899→              !isBindingForceSerialized(section, binding2) &&
   900→              !isSupersetSources(binding2, binding1)
   901→            ) {
   902→              if (!isSameOrChildSection(section, binding2.section)) {
   903→                addOwnersSerializeReason(
   904→                  section,
   905→                  binding2.section,
   906→                  mergeSerializeReasons(
   907→                    // TODO should check for an actual intersection, not just stateful
   908→                    binding1.sources,
   909→                    binding2.sources,
   910→                  ),
   911→                  getAccessorProp().Owner,
   912→                );
   913→              }
   914→              addBindingSerializeReason(
   915→                binding2.section,
   916→                binding2,
   917→                binding1.sources, // TODO should check for an actual intersection, not just binding1.sources stateful
   918→              );
   919→            }
   920→          }
   921→        }
   922→      }
   923→    }
   924→
   925→    forEach(section.referencedLocalClosures, (closure) => {
