  1075→      intersectionMeta.set(intersection, {
  1076→        id: lastBindingIndex + ++intersectionIndex,
  1077→        scopeOffset: getMaxOwnSourceOffset(intersection, section),
  1078→      });
  1079→    }
  1080→  });
  1081→
  1082→  finalizeFunctionRegistry();
  1083→  mergedReferences.clear();
  1084→  readsByExpression.clear();
  1085→  readsByFn.clear();
