  1092→    if (binding.section === section && binding.sources) {
  1093→      const trackScopeOffset = (source: Binding) => {
  1094→        if (
  1095→          source.scopeOffset &&
  1096→          (!scopeOffset || scopeOffset.id < source.scopeOffset.id)
  1097→        ) {
  1098→          scopeOffset = source.scopeOffset;
  1099→        }
  1100→      };
  1101→      forEach(binding.sources.state, trackScopeOffset);
  1102→      forEach(binding.sources.input, trackScopeOffset);
  1103→    }
  1104→  }
  1105→
  1106→  return scopeOffset;
  1107→}
  1108→
  1109→export const intersectionMeta = new WeakMap<
  1110→  Intersection,
  1111→  { id: number; scopeOffset: Binding | undefined }
  1112→>();
