    29→    if (!tag.node.var) {
    30→      throw tag
    31→        .get("name")
    32→        .buildCodeFrameError("The `define` tag requires a tag variable.");
    33→    }
    34→
    35→    const tagBody = tag.get("body");
    36→    const bodySection = startSection(tagBody);
    37→    const varBinding = trackVarReferences(tag, BindingType.derived);
    38→
    39→    if (bodySection) {
    40→      if (varBinding) {
    41→        // TODO: need to do this for attr tags.
    42→        // Should probably allow passing a binding to analyzeAttrTags.
    43→        bodySection.downstreamBinding =
    44→          varBinding.propertyAliases.get("content") || varBinding;
    45→      }
    46→    }
    47→    // TODO: should determine if var bindings are nullable based on attrs.
    48→    trackParamsReferences(tagBody, BindingType.param);
    49→    analyzeAttributeTags(tag);
    50→    const tagExtra = mergeReferences(
    51→      getOrCreateSection(tag),
    52→      tag.node,
    53→      getAllTagReferenceNodes(tag.node),
    54→    );
    55→
    56→    if (varBinding) {
